// JavaScript for Locksmith Staten Island NY Website// Mobile Menu Togglefunction toggleMenu(){const mobileMenu = document.getElementById('mobile-menu');if (mobileMenu){mobileMenu.classList.toggle('hidden');}}// Smooth Scrolling for Anchor Linksdocument.addEventListener('DOMContentLoaded', function(){const anchorLinks = document.querySelectorAll('a[href^="#"]');anchorLinks.forEach(link =>{link.addEventListener('click', function(e){e.preventDefault();const targetId = this.getAttribute('href').substring(1);const targetElement = document.getElementById(targetId);if (targetElement){targetElement.scrollIntoView({behavior: 'smooth',block: 'start'});}});});});// Form Validation (if forms are added later)function validateForm(formId){const form = document.getElementById(formId);if (!form) return true;const requiredFields = form.querySelectorAll('[required]');let isValid = true;requiredFields.forEach(field =>{if (!field.value.trim()){field.classList.add('error');isValid = false;}else{field.classList.remove('error');}});return isValid;}// Phone Number Formattingfunction formatPhoneNumber(input){if (!input) return;let value = input.value.replace(/\D/g, '');if (value.length >= 10){value = value.replace(/(\d{3})(\d{3})(\d{4})/, '($1) $2-$3');}input.value = value;}// Add event listeners when DOM is loadeddocument.addEventListener('DOMContentLoaded', function(){// Phone number inputsconst phoneInputs = document.querySelectorAll('input[type="tel"]');phoneInputs.forEach(input =>{input.addEventListener('input', function(){formatPhoneNumber(this);});});// Form submissionsconst forms = document.querySelectorAll('form');forms.forEach(form =>{form.addEventListener('submit', function(e){if (!validateForm(this.id)){e.preventDefault();alert('Please fill in all required fields.');}});});});// Lazy Loading for Images (if needed)function lazyLoadImages(){const images = document.querySelectorAll('img[data-src], iframe[data-src]');const imageObserver = new IntersectionObserver((entries, observer) =>{entries.forEach(entry =>{if (entry.isIntersecting){const element = entry.target;element.src = element.dataset.src;element.classList.remove('lazy');observer.unobserve(element);}});});images.forEach(element => imageObserver.observe(element));}// Initialize lazy loadingdocument.addEventListener('DOMContentLoaded', lazyLoadImages);// Google Analytics - G-JM684FHXFCfunction initAnalytics(){// Load Google Analytics gtag.js scriptconst gaScript = document.createElement('script');gaScript.async = true;gaScript.src = 'https://www.googletagmanager.com/gtag/js?id=G-JM684FHXFC';document.head.appendChild(gaScript);// Initialize dataLayer and gtag functionwindow.dataLayer = window.dataLayer || [];function gtag(){dataLayer.push(arguments);}window.gtag = gtag;gtag('js', new Date());gtag('config', 'G-JM684FHXFC');console.log('Google Analytics initialized with ID: G-JM684FHXFC');}// Microsoft Clarity - tuq9kjma60function initClarity(){(function(c,l,a,r,i,t,y){c[a]=c[a]||function(){(c[a].q=c[a].q||[]).push(arguments)};t=l.createElement(r);t.async=1;t.src="https://www.clarity.ms/tag/"+i;y=l.getElementsByTagName(r)[0];y.parentNode.insertBefore(t,y);})(window,document,"clarity","script","tuq9kjma60");console.log('Microsoft Clarity initialized with ID: tuq9kjma60');}// Initialize analytics when page loadswindow.addEventListener('load', function(){initAnalytics();initClarity();});// Service Worker Registration (for PWA features)if ('serviceWorker' in navigator){window.addEventListener('load', function(){navigator.serviceWorker.register('/sw.js').then(registration =>{console.log('Service Worker registered successfully:', registration.scope);}).catch(error =>{console.log('Service Worker registration failed:', error);});});}// PWA Install Promptlet deferredPrompt;const installButton = document.getElementById('pwa-install-btn');window.addEventListener('beforeinstallprompt', (e) =>{// Prevent the mini-infobar from appearing on mobilee.preventDefault();// Stash the event so it can be triggered laterdeferredPrompt = e;// Show the install buttonif (installButton){installButton.style.display = 'block';}});// Handle install button clickif (installButton){installButton.addEventListener('click', async () =>{if (!deferredPrompt){return;}// Show the install promptdeferredPrompt.prompt();// Wait for the user to respond to the promptconst{outcome}= await deferredPrompt.userChoice;console.log(`User response to the install prompt: ${outcome}`);// Clear the deferredPromptdeferredPrompt = null;// Hide the install buttoninstallButton.style.display = 'none';});}// Log when the app is installedwindow.addEventListener('appinstalled', () =>{console.log('PWA was installed successfully');deferredPrompt = null;});// Accessibility: Skip to main contentfunction createSkipLink(){const skipLink = document.createElement('a');skipLink.href = '#main-content';skipLink.textContent = 'Skip to main content';skipLink.className = 'skip-link';skipLink.style.cssText = `position: absolute;top: -40px;left: 6px;background: #000;color: #fff;padding: 8px;text-decoration: none;z-index: 100;`;skipLink.addEventListener('focus', function(){this.style.top = '6px';});skipLink.addEventListener('blur', function(){this.style.top = '-40px';});document.body.insertBefore(skipLink, document.body.firstChild);}document.addEventListener('DOMContentLoaded', createSkipLink);// Performance monitoringfunction logPerformance(){if ('performance' in window && 'getEntriesByType' in performance){window.addEventListener('load', function(){setTimeout(() =>{const perfData = performance.getEntriesByType('navigation')[0];console.log('Page load time:', perfData.loadEventEnd - perfData.fetchStart, 'ms');}, 0);});}}logPerformance();// Error handlingwindow.addEventListener('error', function(e){console.error('JavaScript error:', e.error);// Could send to error tracking service});// Contact Form Handler with Formspreedocument.addEventListener('DOMContentLoaded', function(){const contactForm = document.getElementById('contact-form');if (!contactForm) return;// Handle form submissioncontactForm.addEventListener('submit', function(e){// Don't prevent default - let Formspree handle the submission// But add loading state and success handlingconst submitBtn = document.getElementById('submit-btn');const btnText = document.getElementById('btn-text');const btnLoading = document.getElementById('btn-loading');const successMessage = document.getElementById('success-message');const errorMessage = document.getElementById('error-message');const successText = document.getElementById('success-text');const errorText = document.getElementById('error-text');// Check if elements exist before accessing propertiesif (!submitBtn || !btnText || !btnLoading || !successMessage || !errorMessage || !successText || !errorText){console.error('Required form elements not found');return;}// Show loading statesubmitBtn.disabled = true;btnText.classList.add('hidden');btnLoading.classList.remove('hidden');// Hide previous messagessuccessMessage.classList.add('hidden');errorMessage.classList.add('hidden');// Formspree will handle the actual submission// We'll listen for the formspree:submit event});// Listen for Formspree successwindow.addEventListener('formspree:submit', function(e){const submitBtn = document.getElementById('submit-btn');const btnText = document.getElementById('btn-text');const btnLoading = document.getElementById('btn-loading');const successMessage = document.getElementById('success-message');const successText = document.getElementById('success-text');// Reset loading stateif (submitBtn) submitBtn.disabled = false;if (btnText) btnText.classList.remove('hidden');if (btnLoading) btnLoading.classList.add('hidden');// Show success messageif (successText){successText.textContent = 'Thank you for your message! We\'ll get back to you within 24 hours.';}if (successMessage){successMessage.classList.remove('hidden');successMessage.scrollIntoView({behavior: 'smooth', block: 'center'});}// Reset formcontactForm.reset();});// Listen for Formspree errorswindow.addEventListener('formspree:error', function(e){const submitBtn = document.getElementById('submit-btn');const btnText = document.getElementById('btn-text');const btnLoading = document.getElementById('btn-loading');const errorMessage = document.getElementById('error-message');const errorText = document.getElementById('error-text');// Reset loading stateif (submitBtn) submitBtn.disabled = false;if (btnText) btnText.classList.remove('hidden');if (btnLoading) btnLoading.classList.add('hidden');// Show error messageif (errorText){errorText.textContent = 'Sorry, there was an error sending your message. Please try again or call us directly.';}if (errorMessage){errorMessage.classList.remove('hidden');errorMessage.scrollIntoView({behavior: 'smooth', block: 'center'});}});});// Console welcome messageconsole.log('🚗 Locksmith Staten Island NY - Website Loaded Successfully!');